import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../services/api";
import Navbar from "../components/Navbar";

function Home() {
  const navigate = useNavigate();

  const [counts, setCounts] = useState({
    totalAnimals: 0,
    totalEnclosures: 0,
    totalStaff: 0,
    totalFeedingSchedules: 0,
    totalMedicalRecords: 0,
    totalUsers: 0,
  });

  const [animals, setAnimals] = useState([]);
  const [loading, setLoading] = useState(true);

  const username = localStorage.getItem("username");
  const role = localStorage.getItem("role");

  useEffect(() => {
    fetchHomeData();
  }, []);

  const fetchHomeData = async () => {
    try {
      setLoading(true);
      const countsRes = await API.get("/dashboard/counts");
      const animalsRes = await API.get("/animals");

      setCounts(countsRes.data);
      setAnimals(animalsRes.data.slice(0, 4));
    } catch (error) {
      console.error("Error loading home data:", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <section style={styles.hero}>
          <div>
            <h1 style={styles.title}>Welcome{username ? `, ${username}` : ""}</h1>
            <p style={styles.subtitle}>
              Your zoo operations are now organized in one place. Monitor animal
              records, staff, medical reports, feeding plans, and enclosures easily.
            </p>

            <div style={styles.heroButtons}>
              <button style={styles.primaryBtn} onClick={() => navigate("/animals")}>
                Explore Animals
              </button>

              {role === "ADMIN" && (
                <button style={styles.darkBtn} onClick={() => navigate("/admin")}>
                  Open Admin Dashboard
                </button>
              )}
            </div>
          </div>
        </section>

        <section style={styles.section}>
          <h2 style={styles.sectionTitle}>Dashboard Overview</h2>

          {loading ? (
            <p>Loading dashboard...</p>
          ) : (
            <div style={styles.grid}>
              <div style={styles.card}><h3>Animals</h3><p style={styles.number}>{counts.totalAnimals}</p></div>
              <div style={styles.card}><h3>Enclosures</h3><p style={styles.number}>{counts.totalEnclosures}</p></div>
              <div style={styles.card}><h3>Staff</h3><p style={styles.number}>{counts.totalStaff}</p></div>
              <div style={styles.card}><h3>Feeding</h3><p style={styles.number}>{counts.totalFeedingSchedules}</p></div>
              <div style={styles.card}><h3>Medical</h3><p style={styles.number}>{counts.totalMedicalRecords}</p></div>
              <div style={styles.card}><h3>Users</h3><p style={styles.number}>{counts.totalUsers}</p></div>
            </div>
          )}
        </section>

        <section style={styles.section}>
          <h2 style={styles.sectionTitle}>Featured Animals</h2>

          {loading ? (
            <p>Loading animals...</p>
          ) : animals.length === 0 ? (
            <p>No animals found.</p>
          ) : (
            <div style={styles.grid}>
              {animals.map((animal) => (
                <div key={animal.id} style={styles.card}>
                  <h3>{animal.name}</h3>
                  <p><strong>Species:</strong> {animal.species}</p>
                  <p><strong>Age:</strong> {animal.age}</p>
                  <p><strong>Gender:</strong> {animal.gender}</p>
                  <p><strong>Food:</strong> {animal.foodType}</p>
                  <p><strong>Health:</strong> {animal.healthStatus}</p>
                  <p><strong>Enclosure:</strong> {animal.enclosure?.name || "Not Assigned"}</p>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #eef2ff, #f8fafc)",
    fontFamily: "Arial, sans-serif",
  },
  container: {
    width: "90%",
    maxWidth: "1200px",
    margin: "0 auto",
    padding: "30px 0 50px",
  },
  hero: {
    background: "linear-gradient(135deg, #ffffff, #eff6ff)",
    padding: "35px",
    borderRadius: "20px",
    boxShadow: "0 10px 24px rgba(0,0,0,0.08)",
  },
  title: {
    fontSize: "2.4rem",
    color: "#111827",
    marginBottom: "12px",
  },
  subtitle: {
    fontSize: "1.05rem",
    color: "#4b5563",
    lineHeight: "1.8",
    maxWidth: "750px",
  },
  heroButtons: {
    display: "flex",
    gap: "14px",
    marginTop: "20px",
    flexWrap: "wrap",
  },
  primaryBtn: {
    background: "#2563eb",
    color: "#fff",
    border: "none",
    padding: "12px 20px",
    borderRadius: "10px",
    fontWeight: "bold",
    cursor: "pointer",
  },
  darkBtn: {
    background: "#111827",
    color: "#fff",
    border: "none",
    padding: "12px 20px",
    borderRadius: "10px",
    fontWeight: "bold",
    cursor: "pointer",
  },
  section: {
    marginTop: "30px",
  },
  sectionTitle: {
    fontSize: "1.7rem",
    marginBottom: "18px",
    color: "#111827",
  },
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
    gap: "20px",
  },
  card: {
    background: "#fff",
    borderRadius: "16px",
    padding: "22px",
    boxShadow: "0 8px 18px rgba(0,0,0,0.08)",
    lineHeight: "1.7",
  },
  number: {
    fontSize: "2rem",
    fontWeight: "bold",
    color: "#2563eb",
    marginTop: "10px",
  },
};

export default Home;
